INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d67b753e-8dec-421f-beef-28eeba75ed75', '4f5c9039-c6aa-4565-ae64-f4747150025f', 'The result depends on device speed and cannot be predicted.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d82d2f98-e15c-4443-9d56-58b5ec619f94', '1311a078-78bc-474f-bc92-ab7ea921949d', 'React gives the component a fixed snapshot of its state for that render; the values do not change during the render.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1cc72713-c889-4a74-965b-ea51971eef7f', '1311a078-78bc-474f-bc92-ab7ea921949d', 'React gives the component a live reference to its state so it can read the latest value at any time.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('03e25288-61fb-4636-8b59-38bffa27010d', '1311a078-78bc-474f-bc92-ab7ea921949d', 'React passes state as a prop from the parent component on every render.', FALSE, 2);
