INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('153b04a0-9479-457b-83c4-639caf012538', '970032f2-f10b-4d38-92af-efd94fce780d', 'No — each click is a separate event handled independently; React does not batch across distinct events.', TRUE, 0);
