INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8dd9c9f0-a7ef-44ab-94f2-3964e2ca205a', '970032f2-f10b-4d38-92af-efd94fce780d', 'Yes, but only when React is in Concurrent Mode.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e6120311-f159-4d76-8a38-4df1a0c2fc35', '970032f2-f10b-4d38-92af-efd94fce780d', 'It depends on whether both buttons share the same parent component.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('88685363-3525-4286-b465-2572e412e4ab', '75d8a5fc-48cb-4dec-bcd1-1154317e1411', 'React won''t detect the change and won''t trigger a re-render because the object reference hasn''t changed.', TRUE, 0);
