INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1fec2494-973b-4d3e-805c-50128935ac53', '75d8a5fc-48cb-4dec-bcd1-1154317e1411', 'React enforces immutability with a Proxy that throws on any mutation.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6a7b3f35-4a27-4fb6-91a9-b4774e80dd7d', '75d8a5fc-48cb-4dec-bcd1-1154317e1411', 'Mutations are fine, but they must happen before calling the setter function.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('793cdffb-3251-4493-949c-16616694666e', '38d4c93d-2701-4752-9cc7-34ebdabcd3e7', 'Use `setPerson({ ...person, firstName: e.target.value })` to create a new object.', TRUE, 0);
