INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2a22523d-e21d-482b-b99f-b0508ec39e0e', '224fe932-ac9d-4a83-a921-38febef455a0', 'It cannot copy objects that contain arrays.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7ed8e9b3-f4ac-4644-86dd-dd5f04a508e8', '224fe932-ac9d-4a83-a921-38febef455a0', 'It merges conflicting keys by applying the original object''s value, not the overriding one.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('23833aa2-9638-49c8-8ad9-791b1c7ba372', 'bde5c6b0-18c2-4b57-9108-04cb88a5c624', 'Create a new `artwork` object with spread and a new `person` object with spread, then call `setPerson`.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('89d070c7-5e6e-48af-85c2-32869ce9e29a', 'bde5c6b0-18c2-4b57-9108-04cb88a5c624', 'Mutate `person.artwork.city` directly — React tracks deep mutations automatically.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2f6ffbab-9d6b-4d9d-96a5-4c3c29ab2f4d', 'bde5c6b0-18c2-4b57-9108-04cb88a5c624', 'Call `setPerson` with only the changed field: `setPerson({ city: ''New Delhi'' })`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('12af479e-1bc6-40c9-962d-3ccfdf90a026', 'bde5c6b0-18c2-4b57-9108-04cb88a5c624', 'Use `JSON.parse(JSON.stringify(person))` to deep clone, mutate, then call `setPerson`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5ffaf4ae-b4cd-480f-8843-a658e1bb33e7', 'b701bf2e-7606-455d-8ce0-92e367d344ca', 'Immer lets you write apparently mutating syntax against a draft object while automatically producing the required immutable copies.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e8500cc2-8cb0-456f-8d00-f343a72b72bf', 'b701bf2e-7606-455d-8ce0-92e367d344ca', 'Immer is a React devtools plugin that highlights mutated state in the component tree.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9cc64b2e-e76a-4455-bc75-aca76791f480', 'b701bf2e-7606-455d-8ce0-92e367d344ca', 'Immer deep-clones state on every render to prevent accidental sharing.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c70b5eeb-c637-483a-b3dd-7ea0cdb525d4', 'b701bf2e-7606-455d-8ce0-92e367d344ca', 'Immer provides a custom `useState` replacement that accepts class-based state machines.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('404519ba-5e91-4026-9813-e532ba75098f', '585ebb10-ab96-446d-ab5a-3bf6525ce4c5', '`push()`, `pop()`, `splice()`, and `sort()` — they mutate the array in place.', TRUE, 0);
