INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d8da20ad-bf15-4dc5-bb5d-f42a0e8df9b0', '585ebb10-ab96-446d-ab5a-3bf6525ce4c5', '`concat()` and the spread syntax — they are not compatible with React''s reconciler.', FALSE, 2);
