INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('71ece82e-f2e9-4ba6-8253-737e1cd693c5', '30138eb0-f3ee-4504-ab3a-08dddd094965', 'Twice — React discards the second result to help surface impure functions.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1567f9de-e8da-46b1-bece-823ca486fee6', '30138eb0-f3ee-4504-ab3a-08dddd094965', 'Once — Strict Mode only adds extra DOM inspections, not extra function calls.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c0db551d-27d3-440d-893f-dab55bcbe0f6', '30138eb0-f3ee-4504-ab3a-08dddd094965', 'Three times — React runs one dry-run, one test run, and one final run.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e6f5c00c-d5e7-4d95-b42c-5496ebd102e0', '30138eb0-f3ee-4504-ab3a-08dddd094965', 'It depends on the complexity of the initializer function.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c2dc5fe1-4790-4e57-befd-b610253ba8e5', 'b81a95fa-4006-407c-8c18-398c2d873888', 'Declare an Effect, specify the Effect dependencies, add cleanup if needed.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a3bdddaa-c1b3-482e-a6bc-5909502ebbb3', 'b81a95fa-4006-407c-8c18-398c2d873888', 'Import `useEffect`, wrap it in `useMemo`, then add an error boundary.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f16d7796-833d-4df7-8380-bc60b30713aa', 'b81a95fa-4006-407c-8c18-398c2d873888', 'Declare a ref, attach it to a DOM element, call `useEffect` inside an event handler.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1d7abdbb-cec8-4c2a-ae17-9a30419be2e3', 'b81a95fa-4006-407c-8c18-398c2d873888', 'Create a custom hook, export it, then call it from the component.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('04a96603-261c-4422-990a-53deada628f2', '26948941-22ce-4f7d-974d-1c13afd49b9a', 'Only once when the component first mounts.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('207f3bf6-1871-41e7-8ca1-080751df02b2', '26948941-22ce-4f7d-974d-1c13afd49b9a', 'After every render, including the initial render.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('92b1a1d6-5793-4bbf-8d4d-c76a5c31e100', '26948941-22ce-4f7d-974d-1c13afd49b9a', 'Only when state changes, not on the initial render.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('aa0f566b-ea88-4c93-8573-d3ca065c2426', '26948941-22ce-4f7d-974d-1c13afd49b9a', 'Before each render, so the DOM is ready.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7d2abcbb-44d4-4871-96a9-fdf2c31cf335', 'f12bb5d1-6576-4628-a53e-a81521623370', 'It is called before the next render to pre-fetch new props.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('60c60343-38b7-4db6-88dd-9694e7baadf3', 'f12bb5d1-6576-4628-a53e-a81521623370', 'It stops or undoes whatever the setup function was doing, and runs before the Effect fires again or on unmount.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('85a6e23d-3247-4683-a994-37957faa3a10', 'f12bb5d1-6576-4628-a53e-a81521623370', 'It signals to React that the Effect has finished so the next render can begin.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('99c55eea-a293-4f47-8056-b1e32da27553', 'f12bb5d1-6576-4628-a53e-a81521623370', 'It replaces the `componentWillUnmount` lifecycle method and can only run once.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('03862dad-087c-4cc8-9c62-3a66e53032c7', '5e2d83b7-bf71-42a1-bfcb-02a298d58efe', 'To improve performance by warming up the Effect cache.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8737e848-92af-494a-bd96-909454fe8782', '5e2d83b7-bf71-42a1-bfcb-02a298d58efe', 'To stress-test that the cleanup function correctly undoes the setup, helping find bugs caused by missing cleanup.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5b19f549-060f-4477-b7f0-9711733c979f', '5e2d83b7-bf71-42a1-bfcb-02a298d58efe', 'Because React renders components twice in development to compare virtual DOM snapshots.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a44e8370-2ccb-47e8-ae46-5a08aeb190fe', '5e2d83b7-bf71-42a1-bfcb-02a298d58efe', 'To ensure that Effects with empty dependency arrays are treated as pure functions.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8d7fd74d-224a-4ac1-8830-9b830b4d93e8', '128e83f7-01a3-4ebe-9396-ca709b275e5d', 'Effects run synchronously during rendering; event handlers run asynchronously after painting.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d8ab1212-703c-4e87-9268-35d90150e268', '128e83f7-01a3-4ebe-9396-ca709b275e5d', 'Effects are caused by rendering itself rather than a particular user interaction, whereas event handlers respond to specific user actions.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3ec83e67-e3f1-4fa3-8caf-b82fbc04aff2', '128e83f7-01a3-4ebe-9396-ca709b275e5d', 'Event handlers can return cleanup functions; Effects cannot.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3cba0000-f716-44bd-ae5f-82d379b7ba9f', '128e83f7-01a3-4ebe-9396-ca709b275e5d', 'Effects can only be used in class components; event handlers work in both class and function components.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('c89e7a63-0459-4d00-8e5c-ebcf943cf122', 'f675983a-eb06-46ce-b6b0-12f522146dd6', '`undefined`', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('638dfdd0-fe6b-4f11-9b42-d7d9fbe51f17', 'f675983a-eb06-46ce-b6b0-12f522146dd6', 'The cleanup function that was returned from the setup callback.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8363d905-0950-40e4-aaa0-c1c66dd0e259', 'f675983a-eb06-46ce-b6b0-12f522146dd6', 'A ref object pointing to the latest dependency values.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('42760c45-9dac-4446-8ba3-ed9c1dbd3bdb', 'f675983a-eb06-46ce-b6b0-12f522146dd6', 'A boolean indicating whether the Effect ran on this render.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('b6629ff1-a173-4e09-92ff-587255d92229', '6485935a-1ef5-468d-8c0e-2a36cd823f6c', 'The Effect runs only on mount, equivalent to passing `[]`.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('528399cc-102e-41be-9171-e22a29b8c1be', '6485935a-1ef5-468d-8c0e-2a36cd823f6c', 'React throws an error because a dependency array is required.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a514efbe-075e-41cd-b700-7f988c2d3d0e', '6485935a-1ef5-468d-8c0e-2a36cd823f6c', 'The Effect re-runs after every commit of the component.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2caf38e9-098f-4af6-b95f-ffbe5f89eaf9', '6485935a-1ef5-468d-8c0e-2a36cd823f6c', 'The Effect is disabled and never runs.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('f9d9deed-35b1-4adc-b1ae-f8de26ce48ce', 'e004c75f-112a-4563-8cee-e93679ef8b04', 'The interval fires correctly but `count` will always display `0` due to closure staleness.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('5f7abd7a-a120-4410-862a-63138fa98ea5', 'e004c75f-112a-4563-8cee-e93679ef8b04', 'The interval is cleared and restarted every second because `count` changing re-triggers the Effect; the fix is to use the `setCount(c => c + 1)` updater form so `count` is no longer a dependency.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('acd9bf83-b5d5-47e3-99ea-ddae0d15dfe9', 'e004c75f-112a-4563-8cee-e93679ef8b04', 'The Effect runs twice on mount in development and `count` becomes `NaN`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('607fe706-07ec-4e87-96d2-1a8122ffbd84', 'e004c75f-112a-4563-8cee-e93679ef8b04', 'There is no problem; specifying `[count]` is the correct approach for intervals.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e7265332-bbcd-41bd-b4f4-fa4038eed225', '370a937e-9076-404c-8ad4-74b17e1c87b1', 'You can call `useEffect` inside a loop to attach multiple side effects to list items.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7255fce3-e859-4a8a-aee3-497ccead264d', '370a937e-9076-404c-8ad4-74b17e1c87b1', '`useEffect` can only be called at the top level of a component or custom Hook; it cannot be called inside loops or conditions.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7d66bd8c-4086-4e10-9341-6353ea7898e7', '370a937e-9076-404c-8ad4-74b17e1c87b1', '`useEffect` runs during server rendering and requires a cleanup function for SSR safety.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('12327cb5-bdc2-426f-b127-96398e94b773', '370a937e-9076-404c-8ad4-74b17e1c87b1', 'The dependency array must always contain at least one value; an empty array is not allowed.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('84563a49-8d74-4931-83ba-05c2bfd7e450', '0bc3eb98-f9bd-4ae5-8d11-8f39ee7aeed1', 'Whenever you need to fetch data, because `useLayoutEffect` prevents race conditions.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('34dad765-e022-43b7-a73d-6ac5d4768435', '0bc3eb98-f9bd-4ae5-8d11-8f39ee7aeed1', 'When your Effect performs a visual update (such as positioning a tooltip) and the delay before painting causes a visible flicker.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('751ccf7e-abd0-4c74-a756-f0daa515a710', '0bc3eb98-f9bd-4ae5-8d11-8f39ee7aeed1', 'When you want the Effect to run during server rendering as well as on the client.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('893cf81d-e184-4190-a1a1-361f3f289ffd', '0bc3eb98-f9bd-4ae5-8d11-8f39ee7aeed1', 'When you have more than two dependencies, because `useLayoutEffect` is more efficient for complex dependency arrays.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('bc3f6b58-da5c-4393-ac78-67d612776419', 'a93b0a02-c0de-4afd-bae6-0f72c55f268c', '`{ current: 0 }`', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('59320bda-0843-48d6-b8fb-56541734e586', 'a93b0a02-c0de-4afd-bae6-0f72c55f268c', '`[0, setter]` — a tuple similar to `useState`.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('3c3e900f-6978-42ad-b706-b46b4a572cf6', 'a93b0a02-c0de-4afd-bae6-0f72c55f268c', 'A `WeakRef` wrapping the number `0`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d135068f-4fef-4210-844f-22f17ba8957b', 'a93b0a02-c0de-4afd-bae6-0f72c55f268c', '`null` until the component mounts, then `0`.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('28ca4087-8ee4-47bc-908d-012dab8c8abe', '90eeffac-1d51-4494-b733-d0a1eb45a32e', 'React schedules a re-render, similar to calling a state setter.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4866d814-486f-488c-9d2f-3081af8a5dbb', '90eeffac-1d51-4494-b733-d0a1eb45a32e', 'The component re-renders only if the ref is passed as a prop to a child.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('72dd15b7-4806-4d3f-adca-d5d20fc73fbf', '90eeffac-1d51-4494-b733-d0a1eb45a32e', 'React does not re-render the component; the change is invisible to React.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('ab5c71d8-99eb-4e2f-ac50-36c1ef02715b', '90eeffac-1d51-4494-b733-d0a1eb45a32e', 'React batches the change and applies it during the next commit phase.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('d9b2b6ba-5f5e-4a5d-a238-5f04eb4c7d25', 'a1c00a11-ed84-446a-b033-6e2bf66ce720', 'Because `setInterval` returns a DOM node, which must be stored as a ref.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a5d20c80-67cc-481e-a0bc-63ab0dfe7637', 'a1c00a11-ed84-446a-b033-6e2bf66ce720', 'Because the interval ID is not used for rendering; storing it in state would cause extra re-renders with no visual benefit.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('7d86b8d4-49d0-4321-aea2-6fd987d89959', 'a1c00a11-ed84-446a-b033-6e2bf66ce720', 'Because refs can store functions, but state cannot.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('85c36d44-1e74-4573-a0a6-be0ba1f3f2f0', 'a1c00a11-ed84-446a-b033-6e2bf66ce720', 'Because setting state inside `setInterval` is forbidden by React.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a457a74a-ea16-487c-9fb5-41a0a38854b4', 'b5a10bca-8984-4615-912f-61406e6e77f4', 'Storing the current text of a controlled input that the user is typing into.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4e3516e3-16d0-494b-8abd-374e329b858b', 'b5a10bca-8984-4615-912f-61406e6e77f4', 'Storing a timeout ID that an event handler will later pass to `clearTimeout`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1c287d51-a271-4e09-b48c-f889fa22827a', 'b5a10bca-8984-4615-912f-61406e6e77f4', 'Storing a list of items that should be displayed in a `<ul>`.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('463726fb-0319-4eac-af26-fe48452687b1', 'b5a10bca-8984-4615-912f-61406e6e77f4', 'Storing the selected tab index so the active tab is highlighted correctly.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a793fcc5-2425-4b8d-9f40-a6e546e87f20', 'c12631ea-171f-4794-a7dc-4a82d552cce2', 'During event handlers, because refs are asynchronous and may be stale.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1c63519a-ddba-46a9-a519-d959c972c629', 'c12631ea-171f-4794-a7dc-4a82d552cce2', 'Inside a `useEffect`, because Effects run after every render and would conflict.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a4e2ba44-7250-41ef-949a-8f36137e878c', 'c12631ea-171f-4794-a7dc-4a82d552cce2', 'During rendering (i.e. in the component''s render body), because React doesn''t know when `ref.current` changes and the output becomes unpredictable.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2471d453-a822-429b-896b-9f5c85146e79', 'c12631ea-171f-4794-a7dc-4a82d552cce2', 'Inside a callback passed to `setTimeout`, because the ref may be garbage-collected.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('904dfbf1-6257-4a6c-93aa-c1899e6ef1c0', '1e3f5432-79d4-4495-82d5-a6ee0bd3e3d7', 'Call `document.querySelector()` in a `useEffect`, then store the result in state.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('754b9ead-c004-41e9-8481-a2aefc1b1cf3', '1e3f5432-79d4-4495-82d5-a6ee0bd3e3d7', 'Declare a ref with `useRef(null)`, pass it as the `ref` attribute to the JSX element, then read the DOM node from `ref.current`.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('0c038610-2a1d-4f6f-a1ec-e5e58bbcdcc4', '1e3f5432-79d4-4495-82d5-a6ee0bd3e3d7', 'Pass a callback to the `ref` attribute that calls `setState` with the DOM node.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('24c5629e-3de4-493d-8417-3f36bf3324ff', '1e3f5432-79d4-4495-82d5-a6ee0bd3e3d7', 'Declare a ref with `createRef()` inside the render body and pass it to the JSX element on every render.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('e72e71b7-154c-432e-a91b-78aabc28f42e', '33cd430b-5b71-43a1-8305-12520be587cd', 'During the render phase, before returning JSX.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9f664073-a4b1-4aae-99bf-a2ff2246d0f9', '33cd430b-5b71-43a1-8305-12520be587cd', 'Immediately after the component function is called for the first time.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('6d85456d-9c80-473d-b95a-b5a7b86b671a', '33cd430b-5b71-43a1-8305-12520be587cd', 'During the commit phase, after React has applied changes to the DOM.', TRUE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('db364ba7-c9de-4786-98ff-8bfcba9142b9', '33cd430b-5b71-43a1-8305-12520be587cd', 'Only when `useEffect` runs, not before.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8a6fb684-b23c-4d2c-8f3f-306d19092f19', 'c1ffd750-9bd2-431d-a088-7d2195c1e4ed', 'Prefer refs over state for all DOM updates to avoid unnecessary re-renders.', FALSE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a062db5f-52e7-40bd-a84c-91834b8a0e0d', 'c1ffd750-9bd2-431d-a088-7d2195c1e4ed', 'Use refs only for non-destructive actions such as focusing and scrolling; avoid manually modifying DOM nodes managed by React.', TRUE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('2701ed40-aeec-4b15-94b4-6462536ba9c2', 'c1ffd750-9bd2-431d-a088-7d2195c1e4ed', 'Always call `ref.current.remove()` before a conditional render to keep the DOM clean.', FALSE, 2);
