INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('cbbd312a-5af4-4abf-8d06-38f25c105820', '50367fe5-13b2-488b-8cb7-22f85df0fc12', 'It never changes over time.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('1786c49c-e81e-401e-8f8d-6b879c857858', '50367fe5-13b2-488b-8cb7-22f85df0fc12', 'It is owned by a child component, not the parent.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('fc2dec6e-9e97-4db4-b9b1-858a18bbb3c7', '906fcd9f-7746-4e8e-9639-3fc8628b9f15', 'In their closest common parent component.', TRUE, 0);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('9e47648b-bf39-4d7b-8ae5-0bbd1a7b0b8b', '906fcd9f-7746-4e8e-9639-3fc8628b9f15', 'In each component separately to avoid coupling.', FALSE, 1);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('a062d39e-895a-4318-a42b-b3c4dafa3060', '906fcd9f-7746-4e8e-9639-3fc8628b9f15', 'In the child component that renders first in the tree.', FALSE, 2);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('4aa6b8a0-ad02-411e-b789-5d3979c3d4fc', '906fcd9f-7746-4e8e-9639-3fc8628b9f15', 'In a dedicated global state store outside the component tree.', FALSE, 3);
INSERT INTO "question_options" ("id", "question_id", "text", "is_correct", "order_index") VALUES ('8af73e22-c0bb-4e5f-841b-8b8312d456ea', 'c446b73d-4321-4197-9ec4-86a57c3cf055', 'It allows deep child components to update ancestor state by calling setter functions passed down as props.', TRUE, 0);
